BEGIN;
SET client_min_messages TO WARNING;
SET search_path TO public;

DROP TABLE IF EXISTS "bibillrecvinfo" CASCADE;

CREATE TABLE "bibillrecvinfo" (
    "STOREID" varchar(38) NOT NULL,
    "FLOORCODE" varchar(32) NOT NULL,
    "FLOORNAME" varchar(256) NOT NULL,
    "TENANTCODE" varchar(64) NOT NULL,
    "TENANTNAME" varchar(256) NOT NULL,
    "POSITIONCODE" varchar(255) NOT NULL,
    "POSITIONNAME" text NOT NULL,
    "CONTRACTCODE" varchar(64) NOT NULL,
    "SIGNBOARD" varchar(256) NOT NULL,
    "YTCODE" varchar(64) NOT NULL,
    "YTNAME" varchar(256) NOT NULL,
    "SUBJECTCODE" varchar(32) NOT NULL,
    "SUBJECTNAME" varchar(256) NOT NULL,
    "TAXRATE" decimal(24,4) NOT NULL DEFAULT '0.0000',
    "SETTLENO" varchar(32) NOT NULL,
    "BILLYEAR" varchar(32) NOT NULL,
    "BILLMONTH" varchar(32) NOT NULL,
    "BEGINDATE" timestamp without time zone NOT NULL,
    "ENDDATE" timestamp without time zone NOT NULL,
    "LASTPAYDATE" timestamp without time zone NOT NULL,
    "DIRECTION" decimal(24,4) NOT NULL,
    "YS" decimal(24,4) NOT NULL DEFAULT '0.0000',
    "SS" decimal(24,4) NOT NULL DEFAULT '0.0000',
    "SRCNUM" varchar(64) NOT NULL,
    "BILL_NUM" varchar(32) NOT NULL,
    "SRCCLS" varchar(32) NOT NULL,
    "STATETAG" decimal(8,0) NOT NULL DEFAULT '0',
    "LASTUPT_DATE" timestamp without time zone NOT NULL,
    "BILL_DATE" timestamp without time zone NOT NULL,
    "ACCOUNT_DATE" timestamp without time zone NOT NULL,
    "STORE_CODE" varchar(64) NOT NULL,
    "STORE_NAME" varchar(256) DEFAULT NULL,
    "BUILDING_CODE" varchar(128) DEFAULT NULL,
    "BUILDING_NAME" varchar(256) DEFAULT NULL,
    PRIMARY KEY ("STORE_CODE","STOREID","SRCNUM","SRCCLS")
);
COMMENT ON TABLE "bibillrecvinfo" IS '标准报表账单应收信息表';
COMMENT ON COLUMN "bibillrecvinfo"."STOREID" IS '项目ID';
COMMENT ON COLUMN "bibillrecvinfo"."FLOORCODE" IS '楼层代码';
COMMENT ON COLUMN "bibillrecvinfo"."FLOORNAME" IS '楼层名称';
COMMENT ON COLUMN "bibillrecvinfo"."TENANTCODE" IS '商户代码';
COMMENT ON COLUMN "bibillrecvinfo"."TENANTNAME" IS '商户名称';
COMMENT ON COLUMN "bibillrecvinfo"."POSITIONCODE" IS '铺位代码';
COMMENT ON COLUMN "bibillrecvinfo"."POSITIONNAME" IS '铺位名称';
COMMENT ON COLUMN "bibillrecvinfo"."CONTRACTCODE" IS '合同编号';
COMMENT ON COLUMN "bibillrecvinfo"."SIGNBOARD" IS '店招';
COMMENT ON COLUMN "bibillrecvinfo"."YTCODE" IS '业态代码';
COMMENT ON COLUMN "bibillrecvinfo"."YTNAME" IS '业态名称';
COMMENT ON COLUMN "bibillrecvinfo"."SUBJECTCODE" IS '科目代码';
COMMENT ON COLUMN "bibillrecvinfo"."SUBJECTNAME" IS '科目名称';
COMMENT ON COLUMN "bibillrecvinfo"."TAXRATE" IS '税率';
COMMENT ON COLUMN "bibillrecvinfo"."SETTLENO" IS '期号';
COMMENT ON COLUMN "bibillrecvinfo"."BILLYEAR" IS '费用开始年';
COMMENT ON COLUMN "bibillrecvinfo"."BILLMONTH" IS '费用开始月';
COMMENT ON COLUMN "bibillrecvinfo"."BEGINDATE" IS '费用开始日期';
COMMENT ON COLUMN "bibillrecvinfo"."ENDDATE" IS '费用终止日期';
COMMENT ON COLUMN "bibillrecvinfo"."LASTPAYDATE" IS '最后缴款日';
COMMENT ON COLUMN "bibillrecvinfo"."DIRECTION" IS '收付方向';
COMMENT ON COLUMN "bibillrecvinfo"."YS" IS '应收金额';
COMMENT ON COLUMN "bibillrecvinfo"."SS" IS '已收金额';
COMMENT ON COLUMN "bibillrecvinfo"."SRCNUM" IS '来源单号';
COMMENT ON COLUMN "bibillrecvinfo"."BILL_NUM" IS '账单号';
COMMENT ON COLUMN "bibillrecvinfo"."SRCCLS" IS '来源类型';
COMMENT ON COLUMN "bibillrecvinfo"."STATETAG" IS '状态标志';
COMMENT ON COLUMN "bibillrecvinfo"."LASTUPT_DATE" IS '最后修改日期';
COMMENT ON COLUMN "bibillrecvinfo"."BILL_DATE" IS '开单日期';
COMMENT ON COLUMN "bibillrecvinfo"."ACCOUNT_DATE" IS '应收记账日期';
COMMENT ON COLUMN "bibillrecvinfo"."STORE_CODE" IS '项目代码';
COMMENT ON COLUMN "bibillrecvinfo"."STORE_NAME" IS '楼宇代码';
COMMENT ON COLUMN "bibillrecvinfo"."BUILDING_CODE" IS '楼宇代码';
COMMENT ON COLUMN "bibillrecvinfo"."BUILDING_NAME" IS '楼宇名称';
CREATE INDEX "idx_bibillrecvinfo_index_bibillrecvinfo_contract" ON "bibillrecvinfo" ("STOREID","CONTRACTCODE");
CREATE INDEX "idx_bibillrecvinfo_index_bibillrecvinfo_settleno" ON "bibillrecvinfo" ("SETTLENO");
CREATE INDEX "idx_bibillrecvinfo_index_bibillrecvinfo_srcnum" ON "bibillrecvinfo" ("SRCNUM");

DROP TABLE IF EXISTS "bicategory" CASCADE;

CREATE TABLE "bicategory" (
    "STOREID" varchar(38) NOT NULL,
    "CODE" varchar(32) NOT NULL,
    "NAME" varchar(64) NOT NULL,
    "LVL" varchar(32) NOT NULL,
    "MEMO" text,
    "SRC" decimal(8,0) DEFAULT '0',
    "ENABLED" decimal(2,0) NOT NULL,
    PRIMARY KEY ("STOREID","CODE")
);
COMMENT ON TABLE "bicategory" IS '标准报表业态表';
COMMENT ON COLUMN "bicategory"."STOREID" IS '项目ID';
COMMENT ON COLUMN "bicategory"."CODE" IS '业态代码';
COMMENT ON COLUMN "bicategory"."NAME" IS '业态名称';
COMMENT ON COLUMN "bicategory"."LVL" IS '业态等级';
COMMENT ON COLUMN "bicategory"."MEMO" IS '备注';
COMMENT ON COLUMN "bicategory"."SRC" IS '来源';
COMMENT ON COLUMN "bicategory"."ENABLED" IS '状态';

DROP TABLE IF EXISTS "bicrmconsumedtl" CASCADE;

CREATE TABLE "bicrmconsumedtl" (
    "FILDATE" timestamp without time zone NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "CARRIER" varchar(32) NOT NULL,
    "STOREID" varchar(32) NOT NULL,
    "BUILDING_CODE" varchar(32) DEFAULT NULL,
    "BUILDING_NAME" varchar(256) DEFAULT NULL,
    "FLOORCODE" varchar(32) NOT NULL,
    "FLOORNAME" varchar(256) NOT NULL,
    "YTCODE" varchar(64) NOT NULL,
    "YTNAME" varchar(64) NOT NULL,
    "SIGNBOARD" varchar(512) NOT NULL,
    "AMT" decimal(24,4) NOT NULL DEFAULT '0.0000',
    "SCORE" decimal(24,4) DEFAULT '0.0000',
    "SRCNUM" varchar(32) NOT NULL,
    "SRC" varchar(32) NOT NULL DEFAULT '前台消费',
    "STORE_CODE" varchar(40) DEFAULT NULL,
    "STORE_NAME" varchar(200) DEFAULT NULL,
    "CONT_NO" varchar(128) NOT NULL,
    "TRADE_TYPE" varchar(128) DEFAULT NULL,
    "TRADE_SUB_TYPE" varchar(128) DEFAULT NULL,
    "SRC_CHANNEL" varchar(255) DEFAULT NULL,
    "GRADE_CODE" varchar(64) DEFAULT NULL,
    "GRADE_NAME" varchar(255) DEFAULT NULL,
    "LASTUPT_DATE" timestamp without time zone NOT NULL DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY ("STOREID","CONT_NO","CARRIER","FILDATE","SRCNUM")
);
COMMENT ON TABLE "bicrmconsumedtl" IS '标准报表会员消费明细信息表';
COMMENT ON COLUMN "bicrmconsumedtl"."FILDATE" IS '发生日期';
COMMENT ON COLUMN "bicrmconsumedtl"."CARRIER" IS '会员ID';
COMMENT ON COLUMN "bicrmconsumedtl"."STOREID" IS '项目ID';
COMMENT ON COLUMN "bicrmconsumedtl"."BUILDING_CODE" IS '楼宇代码';
COMMENT ON COLUMN "bicrmconsumedtl"."BUILDING_NAME" IS '楼宇名称';
COMMENT ON COLUMN "bicrmconsumedtl"."FLOORCODE" IS '楼层代码';
COMMENT ON COLUMN "bicrmconsumedtl"."FLOORNAME" IS '楼层名称';
COMMENT ON COLUMN "bicrmconsumedtl"."YTCODE" IS '业态代码';
COMMENT ON COLUMN "bicrmconsumedtl"."YTNAME" IS '业态名称';
COMMENT ON COLUMN "bicrmconsumedtl"."SIGNBOARD" IS '品牌';
COMMENT ON COLUMN "bicrmconsumedtl"."AMT" IS '消费金额';
COMMENT ON COLUMN "bicrmconsumedtl"."SCORE" IS '积分';
COMMENT ON COLUMN "bicrmconsumedtl"."SRCNUM" IS '流水';
COMMENT ON COLUMN "bicrmconsumedtl"."SRC" IS '数据来源';
COMMENT ON COLUMN "bicrmconsumedtl"."STORE_CODE" IS '项目代码';
COMMENT ON COLUMN "bicrmconsumedtl"."STORE_NAME" IS '项目名称';
COMMENT ON COLUMN "bicrmconsumedtl"."CONT_NO" IS '合同号';
COMMENT ON COLUMN "bicrmconsumedtl"."TRADE_TYPE" IS '交易变动类型';
COMMENT ON COLUMN "bicrmconsumedtl"."TRADE_SUB_TYPE" IS '交易变动子类型';
COMMENT ON COLUMN "bicrmconsumedtl"."SRC_CHANNEL" IS '来源渠道方';
COMMENT ON COLUMN "bicrmconsumedtl"."GRADE_CODE" IS '会员等级代码';
COMMENT ON COLUMN "bicrmconsumedtl"."GRADE_NAME" IS '会员等级名称';
COMMENT ON COLUMN "bicrmconsumedtl"."LASTUPT_DATE" IS '最后修改日期';
CREATE INDEX "idx_bicrmconsumedtl_idx_bicrmconsumedtl_fildate" ON "bicrmconsumedtl" ("FILDATE");
CREATE INDEX "idx_bicrmconsumedtl_idx_consumedtl_carrier" ON "bicrmconsumedtl" ("CARRIER");

