DROP TABLE IF EXISTS "bilocation" CASCADE;

CREATE TABLE "bilocation" (
    "STOREID" varchar(38) NOT NULL,
    "CODE" varchar(32) NOT NULL,
    "NAME" varchar(256) NOT NULL,
    "FLOORCODE" varchar(32) NOT NULL,
    "APPORTIONAREA" decimal(24,4) NOT NULL DEFAULT '0.0000',
    "AREA" decimal(24,4) NOT NULL DEFAULT '0.0000',
    "BUILDAREA" decimal(24,4) NOT NULL DEFAULT '0.0000',
    "POSITIONTYPE" varchar(32) NOT NULL,
    "STATNAME" varchar(32) NOT NULL,
    "SRC" decimal(8,0) NOT NULL DEFAULT '0',
    "SUB_TYPE" varchar(256) DEFAULT NULL,
    "STORE_CODE" varchar(100) DEFAULT NULL,
    "STORE_NAME" varchar(256) DEFAULT NULL,
    "VALID_BEGIN_DATE" timestamp without time zone NOT NULL DEFAULT '1900-01-01 00:00:00',
    "VALID_END_DATE" timestamp without time zone NOT NULL DEFAULT '2099-12-31 00:00:00',
    "DATA_FLAG" decimal(2,0) DEFAULT NULL,
    "BUILDING_CODE" varchar(128) DEFAULT NULL,
    "BUILDING_NAME" varchar(256) DEFAULT NULL,
    "FLOORNAME" varchar(256) DEFAULT NULL,
    PRIMARY KEY ("STOREID","CODE","VALID_BEGIN_DATE")
);
COMMENT ON TABLE "bilocation" IS '标准报表地理位置';
COMMENT ON COLUMN "bilocation"."STOREID" IS '项目ID';
COMMENT ON COLUMN "bilocation"."CODE" IS '位置代码';
COMMENT ON COLUMN "bilocation"."NAME" IS '位置名称';
COMMENT ON COLUMN "bilocation"."FLOORCODE" IS '楼层代码';
COMMENT ON COLUMN "bilocation"."APPORTIONAREA" IS '使用面积';
COMMENT ON COLUMN "bilocation"."AREA" IS '计租面积';
COMMENT ON COLUMN "bilocation"."BUILDAREA" IS '建筑面积';
COMMENT ON COLUMN "bilocation"."POSITIONTYPE" IS '铺位类型';
COMMENT ON COLUMN "bilocation"."STATNAME" IS '铺位状态名称';
COMMENT ON COLUMN "bilocation"."SRC" IS '来源';
COMMENT ON COLUMN "bilocation"."SUB_TYPE" IS '类型定义';
COMMENT ON COLUMN "bilocation"."STORE_CODE" IS '项目代码';
COMMENT ON COLUMN "bilocation"."STORE_NAME" IS '项目名称';
COMMENT ON COLUMN "bilocation"."VALID_BEGIN_DATE" IS '有效起始日期';
COMMENT ON COLUMN "bilocation"."VALID_END_DATE" IS '有效截止日期';
COMMENT ON COLUMN "bilocation"."DATA_FLAG" IS '有效无效';
COMMENT ON COLUMN "bilocation"."BUILDING_CODE" IS '楼宇代码';
COMMENT ON COLUMN "bilocation"."BUILDING_NAME" IS '楼宇名称';
COMMENT ON COLUMN "bilocation"."FLOORNAME" IS '楼层名称';

