DROP TABLE IF EXISTS "bi_iv_goldennotice" CASCADE;

CREATE TABLE "bi_iv_goldennotice" (
    "UUID" varchar(38) NOT NULL,
    "APPKEY" varchar(64) DEFAULT NULL,
    "MESSAGE" varchar(1024) DEFAULT NULL,
    "NOTIFY_TYPE" varchar(32) DEFAULT NULL,
    "NOTIFY_TIME" varchar(20) DEFAULT NULL,
    "ORDER_ID" varchar(64) DEFAULT NULL,
    "G_UNIQUE_ID" varchar(32) DEFAULT NULL,
    "TICKET_SN" varchar(16) DEFAULT NULL,
    "TICKET_CODE" varchar(16) DEFAULT NULL,
    "TICKET_DATE" varchar(20) DEFAULT NULL,
    "TICKET_STATUS" decimal(8,0) DEFAULT NULL,
    "TICKET_TOTAL_AMOUNT_HAS_TAX" varchar(20) DEFAULT NULL,
    "TICKET_TOTAL_AMOUNT_NO_TAX" varchar(20) DEFAULT NULL,
    "TICKET_TAX_AMOUNT" varchar(20) DEFAULT NULL,
    "CHECK_CODE" varchar(64) DEFAULT NULL,
    "PDF_URL" varchar(256) DEFAULT NULL,
    "INVOICE_TYPE_CODE" varchar(4) DEFAULT NULL,
    "BUYER_NAME" varchar(128) DEFAULT NULL,
    "BUYER_TAXPAYER_NUM" varchar(64) DEFAULT NULL,
    "BUYER_BANK_NAME" varchar(128) DEFAULT NULL,
    "BUYER_BANK_ACCOUNT" varchar(128) DEFAULT NULL,
    "BUYER_ADDRESS" varchar(1024) DEFAULT NULL,
    "BUYER_PHONE" varchar(64) DEFAULT NULL,
    "BUYER_EMAIL" varchar(64) DEFAULT NULL,
    "LASTMODIFIED" timestamp without time zone NOT NULL,
    "QRCODE" text,
    PRIMARY KEY ("UUID")
);
COMMENT ON TABLE "bi_iv_goldennotice" IS '发票平台返回数据';
COMMENT ON COLUMN "bi_iv_goldennotice"."UUID" IS '唯一标识';
COMMENT ON COLUMN "bi_iv_goldennotice"."APPKEY" IS '服务商appkey';
COMMENT ON COLUMN "bi_iv_goldennotice"."MESSAGE" IS '返回结果详情';
COMMENT ON COLUMN "bi_iv_goldennotice"."NOTIFY_TYPE" IS '通知类型，invoice.invalid（作废回调）、invoice.blue（蓝票回调）或者invoice.red（红票回调）';
COMMENT ON COLUMN "bi_iv_goldennotice"."NOTIFY_TIME" IS '通知时间';
COMMENT ON COLUMN "bi_iv_goldennotice"."ORDER_ID" IS '商户交易流水号,对应发票UUID';
COMMENT ON COLUMN "bi_iv_goldennotice"."G_UNIQUE_ID" IS '发票平台交易流水号';
COMMENT ON COLUMN "bi_iv_goldennotice"."TICKET_SN" IS '发票号码';
COMMENT ON COLUMN "bi_iv_goldennotice"."TICKET_CODE" IS '发票代码';
COMMENT ON COLUMN "bi_iv_goldennotice"."TICKET_DATE" IS '作废时间';
COMMENT ON COLUMN "bi_iv_goldennotice"."TICKET_STATUS" IS '发票状态（1开票中,2开票成功 -2开票失败 6：作废中 7作废成功 8作废失败）';
COMMENT ON COLUMN "bi_iv_goldennotice"."TICKET_TOTAL_AMOUNT_HAS_TAX" IS '发票含税总价 开票失败时值为空';
COMMENT ON COLUMN "bi_iv_goldennotice"."TICKET_TOTAL_AMOUNT_NO_TAX" IS '发票去税总价 开票失败时值为空';
COMMENT ON COLUMN "bi_iv_goldennotice"."TICKET_TAX_AMOUNT" IS '发票税额 开票失败时值为空';
COMMENT ON COLUMN "bi_iv_goldennotice"."CHECK_CODE" IS '发票校验码 开票失败时值为空';
COMMENT ON COLUMN "bi_iv_goldennotice"."PDF_URL" IS '发票url地址 开票失败时值为空（纸票没有pdf）';
COMMENT ON COLUMN "bi_iv_goldennotice"."INVOICE_TYPE_CODE" IS '发票类型,004:增值税专用发票，007:增值税普通发票，026：增值税电子发票，025：增值税卷式发票, 032:区块链发票 默认为026）';
COMMENT ON COLUMN "bi_iv_goldennotice"."BUYER_NAME" IS '购买方名称';
COMMENT ON COLUMN "bi_iv_goldennotice"."BUYER_TAXPAYER_NUM" IS '购买方纳税人识别号';
COMMENT ON COLUMN "bi_iv_goldennotice"."BUYER_BANK_NAME" IS '购买方开户行';
COMMENT ON COLUMN "bi_iv_goldennotice"."BUYER_BANK_ACCOUNT" IS '购买方开户账户';
COMMENT ON COLUMN "bi_iv_goldennotice"."BUYER_ADDRESS" IS '购买方地址';
COMMENT ON COLUMN "bi_iv_goldennotice"."BUYER_PHONE" IS '购买方联系电话';
COMMENT ON COLUMN "bi_iv_goldennotice"."BUYER_EMAIL" IS '购买方邮箱';
COMMENT ON COLUMN "bi_iv_goldennotice"."LASTMODIFIED" IS '最后修改时间';
COMMENT ON COLUMN "bi_iv_goldennotice"."QRCODE" IS '发票二维码base64内容,最大10Kb。渠道不同可能返回为空';
CREATE INDEX "idx_bi_iv_goldennotice_idx_bi_iv_goldennotice_1" ON "bi_iv_goldennotice" ("ORDER_ID");

