    "STORE_NAME" varchar(256) DEFAULT NULL,
    "BILL_NUM" varchar(32) NOT NULL,
    "STATE" varchar(64) NOT NULL,
    "CATEGORY" varchar(64) NOT NULL,
    "BUILDING_NAME" varchar(128) DEFAULT NULL,
    "BUILDING_CODE" varchar(32) DEFAULT NULL,
    "FLOOR_NAME" varchar(128) DEFAULT NULL,
    "FLOOR_CODE" varchar(32) DEFAULT NULL,
    "APPLICATION_TIME" timestamp without time zone DEFAULT NULL,
    "DEADLINE_TIME" timestamp without time zone DEFAULT NULL,
    "DEAL_TIME" timestamp without time zone NOT NULL,
    "REMARK" varchar(1024) DEFAULT NULL,
    "CREATE_DATE" timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    "LASTUPT_DATE" timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY ("STORE_CODE","BILL_NUM")
);
COMMENT ON TABLE "bi_i_operinspect" IS '标准报表运营巡检单';
COMMENT ON COLUMN "bi_i_operinspect"."STORE_CODE" IS '项目代码';
COMMENT ON COLUMN "bi_i_operinspect"."STORE_NAME" IS '项目名称';
COMMENT ON COLUMN "bi_i_operinspect"."BILL_NUM" IS '单据号';
COMMENT ON COLUMN "bi_i_operinspect"."STATE" IS '单据状态';
COMMENT ON COLUMN "bi_i_operinspect"."CATEGORY" IS '巡检类型';
COMMENT ON COLUMN "bi_i_operinspect"."BUILDING_NAME" IS '楼宇名称';
COMMENT ON COLUMN "bi_i_operinspect"."BUILDING_CODE" IS '楼宇代码';
COMMENT ON COLUMN "bi_i_operinspect"."FLOOR_NAME" IS '楼层名称';
COMMENT ON COLUMN "bi_i_operinspect"."FLOOR_CODE" IS '楼层代码';
COMMENT ON COLUMN "bi_i_operinspect"."APPLICATION_TIME" IS '申请时间';
COMMENT ON COLUMN "bi_i_operinspect"."DEADLINE_TIME" IS '最晚处理时间';
COMMENT ON COLUMN "bi_i_operinspect"."DEAL_TIME" IS '实际处理时间';
COMMENT ON COLUMN "bi_i_operinspect"."REMARK" IS '说明';
COMMENT ON COLUMN "bi_i_operinspect"."CREATE_DATE" IS '创建时间';
COMMENT ON COLUMN "bi_i_operinspect"."LASTUPT_DATE" IS '最后修改时间';

DROP TABLE IF EXISTS "bi_i_opermaintainbill" CASCADE;

CREATE TABLE "bi_i_opermaintainbill" (
    "STORE_CODE" varchar(64) NOT NULL,
    "STORE_NAME" varchar(256) DEFAULT NULL,
    "BILL_NUM" varchar(32) NOT NULL,
    "STATE" varchar(64) NOT NULL,
    "APPLICANT_CODE" varchar(32) DEFAULT NULL,
    "APPLICANT_NAME" varchar(256) DEFAULT NULL,
    "REPORT_DATE" timestamp without time zone DEFAULT NULL,
    "CONTRACT_CODE" varchar(32) DEFAULT NULL,
    "TENANT_NAME" varchar(128) DEFAULT NULL,
    "TENANT_CODE" varchar(32) DEFAULT NULL,
    "CONTACTINFO" varchar(256) DEFAULT NULL,
    "PRIORITY" varchar(32) DEFAULT NULL,
    "MAITAIN_CONTENT" varchar(2048) DEFAULT NULL,
    "MAINTAIN_TYPE" varchar(256) DEFAULT NULL,
    "SERVICE_MAN" varchar(256) DEFAULT NULL,
    "MAITAIN_ADDRESS" varchar(256) DEFAULT NULL,
    "MAINTAIN_BEGIN_TIME" timestamp without time zone DEFAULT NULL,
    "MAINTAIN_END_TIME" timestamp without time zone DEFAULT NULL,
    "COMPLETIONINFO" varchar(2048) DEFAULT NULL,
    "TOTAL_FEE" decimal(19,2) DEFAULT NULL,
    "TOTAL_CHARGE" decimal(19,2) DEFAULT NULL,
    "APPOINTMENT_TIME" timestamp without time zone DEFAULT NULL,
    "ARTIFICIAL_FEE_CHARGE" decimal(8,0) NOT NULL,
    "ARTIFICIAL_FEE" decimal(19,2) DEFAULT NULL,
    "PARTS_FEE_CHARGE" decimal(8,0) DEFAULT NULL,
    "PARTS_FEE" decimal(19,2) DEFAULT NULL,
    "MATERIAL_FEE_CHARGE" decimal(8,0) NOT NULL,
    "MATERIAL_FEE" decimal(19,2) DEFAULT NULL,
    "INCOME_DATE" timestamp without time zone DEFAULT NULL,
    "EVALUATION" varchar(32) DEFAULT NULL,
    "SOLVE" decimal(8,0) DEFAULT NULL,
    "REMARK" varchar(2048) DEFAULT NULL,
    "CREATE_DATE" timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    "LASTUPT_DATE" timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY ("STORE_CODE","BILL_NUM")
);
COMMENT ON TABLE "bi_i_opermaintainbill" IS '标准报表商户维修单';
