COMMENT ON COLUMN "bi_i_opermaintainbill"."APPLICANT_CODE" IS '报修人代码';
COMMENT ON COLUMN "bi_i_opermaintainbill"."APPLICANT_NAME" IS '报修人名称';
COMMENT ON COLUMN "bi_i_opermaintainbill"."REPORT_DATE" IS '报修日期';
COMMENT ON COLUMN "bi_i_opermaintainbill"."CONTRACT_CODE" IS '合同代码';
COMMENT ON COLUMN "bi_i_opermaintainbill"."TENANT_NAME" IS '商户名称';
COMMENT ON COLUMN "bi_i_opermaintainbill"."TENANT_CODE" IS '商户代码';
COMMENT ON COLUMN "bi_i_opermaintainbill"."CONTACTINFO" IS '商户联系方式';
