COMMENT ON COLUMN "bi_i_opermaintainbill"."MAITAIN_CONTENT" IS '描述';
COMMENT ON COLUMN "bi_i_opermaintainbill"."MAINTAIN_TYPE" IS '维修类型';
COMMENT ON COLUMN "bi_i_opermaintainbill"."SERVICE_MAN" IS '维修人';
COMMENT ON COLUMN "bi_i_opermaintainbill"."MAITAIN_ADDRESS" IS '维修地址';
COMMENT ON COLUMN "bi_i_opermaintainbill"."MAINTAIN_BEGIN_TIME" IS '维修开始时间';
COMMENT ON COLUMN "bi_i_opermaintainbill"."MAINTAIN_END_TIME" IS '维修结束时间';
COMMENT ON COLUMN "bi_i_opermaintainbill"."COMPLETIONINFO" IS '完成情况';
COMMENT ON COLUMN "bi_i_opermaintainbill"."TOTAL_FEE" IS '费用总额';
COMMENT ON COLUMN "bi_i_opermaintainbill"."TOTAL_CHARGE" IS '收费总额';
COMMENT ON COLUMN "bi_i_opermaintainbill"."APPOINTMENT_TIME" IS '期望维修时间';
