COMMENT ON COLUMN "bi_i_opermaintainbill"."LASTUPT_DATE" IS '最后修改时间';

DROP TABLE IF EXISTS "bi_i_passenger_day" CASCADE;

CREATE TABLE "bi_i_passenger_day" (
    "STORE_CODE" varchar(64) NOT NULL,
    "STORE_NAME" varchar(255) DEFAULT NULL,
    "IN_DATE" timestamp without time zone NOT NULL,
    "LAST_IN_DATE" timestamp without time zone DEFAULT NULL,
    "PERSON_CODE" varchar(64) NOT NULL,
    "SEX" decimal(1,0) DEFAULT NULL,
    "AGE" decimal(19,0) DEFAULT NULL,
    "GENERATION" varchar(64) DEFAULT NULL,
    "TRAFFIC" varchar(64) DEFAULT NULL,
    "LIFECYCLE" varchar(64) DEFAULT NULL,
    "IN_TIME" timestamp without time zone DEFAULT NULL,
    "IN_DOOR" varchar(64) DEFAULT NULL,
    "OUT_TIME" timestamp without time zone DEFAULT NULL,
    "OUT_DOOR" varchar(64) DEFAULT NULL,
    "IN_TIMES" decimal(19,0) DEFAULT NULL,
    "STAY_HOURS" decimal(24,4) DEFAULT NULL,
    "IS_NEW" decimal(2,0) DEFAULT '0',
    "CREATE_DATE" timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    "LASTUPT_DATE" timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    "DATA_FLAG" decimal(2,0) NOT NULL DEFAULT '1',
    PRIMARY KEY ("STORE_CODE","PERSON_CODE","IN_DATE")
);
COMMENT ON TABLE "bi_i_passenger_day" IS '顾客日表';
COMMENT ON COLUMN "bi_i_passenger_day"."STORE_CODE" IS '注册项目代码';
COMMENT ON COLUMN "bi_i_passenger_day"."STORE_NAME" IS '注册项目名称';
COMMENT ON COLUMN "bi_i_passenger_day"."IN_DATE" IS '到店日期';
COMMENT ON COLUMN "bi_i_passenger_day"."LAST_IN_DATE" IS '上次到店日期';
COMMENT ON COLUMN "bi_i_passenger_day"."PERSON_CODE" IS '顾客代码';
COMMENT ON COLUMN "bi_i_passenger_day"."SEX" IS '性别(1:女；2:男)';
COMMENT ON COLUMN "bi_i_passenger_day"."AGE" IS '会员年龄';
COMMENT ON COLUMN "bi_i_passenger_day"."GENERATION" IS '年代';
COMMENT ON COLUMN "bi_i_passenger_day"."TRAFFIC" IS '交通方式';
COMMENT ON COLUMN "bi_i_passenger_day"."LIFECYCLE" IS '生命周期';
COMMENT ON COLUMN "bi_i_passenger_day"."IN_TIME" IS '到店时间(第一次到店)';
COMMENT ON COLUMN "bi_i_passenger_day"."IN_DOOR" IS '入口';
COMMENT ON COLUMN "bi_i_passenger_day"."OUT_TIME" IS '离店时间（最后一次离店）';
COMMENT ON COLUMN "bi_i_passenger_day"."OUT_DOOR" IS '出口';
COMMENT ON COLUMN "bi_i_passenger_day"."IN_TIMES" IS '进入次数';
COMMENT ON COLUMN "bi_i_passenger_day"."STAY_HOURS" IS '停留时长（小时）';
COMMENT ON COLUMN "bi_i_passenger_day"."IS_NEW" IS '0:老客，1:新客';
COMMENT ON COLUMN "bi_i_passenger_day"."CREATE_DATE" IS '创建日期,格式：2018-01-01 12:12:12';
COMMENT ON COLUMN "bi_i_passenger_day"."LASTUPT_DATE" IS '最后更新日期,格式：2018-01-01 12:12:12';
COMMENT ON COLUMN "bi_i_passenger_day"."DATA_FLAG" IS '数据状态，1有效0失效';
CREATE INDEX "idx_bi_i_passenger_day_idx_bi_i_passenger_day" ON "bi_i_passenger_day" ("IN_DATE");

DROP TABLE IF EXISTS "bi_i_passenger_site" CASCADE;

CREATE TABLE "bi_i_passenger_site" (
    "STORE_CODE" varchar(64) NOT NULL,
    "STORE_NAME" varchar(255) DEFAULT NULL,
    "SITE_CODE" varchar(128) NOT NULL,
    "SITE_NAME" varchar(128) DEFAULT NULL,
    "TIME_TYPE" decimal(6,0) NOT NULL DEFAULT '10',
    "BEGIN_DATE" timestamp without time zone NOT NULL,
    "END_DATE" timestamp without time zone NOT NULL,
    "IN_NUMS" decimal(12,0) DEFAULT '0',
    "OUT_NUMS" decimal(12,0) DEFAULT '0',
    "CREATE_DATE" timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    "LASTUPT_DATE" timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    "DATA_FLAG" decimal(2,0) NOT NULL DEFAULT '1',
    PRIMARY KEY ("STORE_CODE","SITE_CODE","TIME_TYPE","BEGIN_DATE")
);
COMMENT ON TABLE "bi_i_passenger_site" IS '点位客流明细表';
COMMENT ON COLUMN "bi_i_passenger_site"."STORE_CODE" IS '项目代码';
COMMENT ON COLUMN "bi_i_passenger_site"."STORE_NAME" IS '项目名称';
COMMENT ON COLUMN "bi_i_passenger_site"."SITE_CODE" IS '位置代码';
COMMENT ON COLUMN "bi_i_passenger_site"."SITE_NAME" IS '位置名称';
COMMENT ON COLUMN "bi_i_passenger_site"."TIME_TYPE" IS '时间类型:每隔xx(5、10、30、60......)分钟上传一次数据';
COMMENT ON COLUMN "bi_i_passenger_site"."BEGIN_DATE" IS '开始时间,格式：2018-01-01 12:12:12';
COMMENT ON COLUMN "bi_i_passenger_site"."END_DATE" IS '结束时间,格式：2018-01-01 12:12:12';
COMMENT ON COLUMN "bi_i_passenger_site"."IN_NUMS" IS '进入人数';
COMMENT ON COLUMN "bi_i_passenger_site"."OUT_NUMS" IS '离开人数';
COMMENT ON COLUMN "bi_i_passenger_site"."CREATE_DATE" IS '创建时间,格式：2018-01-01 12:12:12';
COMMENT ON COLUMN "bi_i_passenger_site"."LASTUPT_DATE" IS '最后更新日期,格式：2018-01-01 12:12:12';
COMMENT ON COLUMN "bi_i_passenger_site"."DATA_FLAG" IS '数据状态：1表示数据可读取；2表示对已经传入中间库的数据进行了修改；3表示数据错误，进行了逻辑删除';

DROP TABLE IF EXISTS "bi_i_passenger_track" CASCADE;

CREATE TABLE "bi_i_passenger_track" (
    "PK_ID" varchar(128) NOT NULL,
