    "CREATE_DATE" timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    "LASTUPT_DATE" timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    "DATA_FLAG" decimal(2,0) NOT NULL DEFAULT '1',
    PRIMARY KEY ("PK_ID")
);
COMMENT ON TABLE "bi_i_passenger_track" IS '顾客轨迹表';
COMMENT ON COLUMN "bi_i_passenger_track"."PK_ID" IS '拼接主键';
COMMENT ON COLUMN "bi_i_passenger_track"."STORE_CODE" IS '项目代码';
COMMENT ON COLUMN "bi_i_passenger_track"."STORE_NAME" IS '项目名称';
COMMENT ON COLUMN "bi_i_passenger_track"."CAL_DATE" IS '到店日期';
COMMENT ON COLUMN "bi_i_passenger_track"."PERSON_CODE" IS '顾客代码';
COMMENT ON COLUMN "bi_i_passenger_track"."SITE_CODE" IS '点位代码';
COMMENT ON COLUMN "bi_i_passenger_track"."SITE_NAME" IS '点位名称';
COMMENT ON COLUMN "bi_i_passenger_track"."EVENT_CODE" IS '轨迹ID:1进 2出 3路过';
COMMENT ON COLUMN "bi_i_passenger_track"."EVENT_TIME" IS '发生时间';
COMMENT ON COLUMN "bi_i_passenger_track"."CREATE_DATE" IS '创建日期,格式：2018-01-01 12:12:12';
COMMENT ON COLUMN "bi_i_passenger_track"."LASTUPT_DATE" IS '最后更新日期,格式：2018-01-01 12:12:12';
COMMENT ON COLUMN "bi_i_passenger_track"."DATA_FLAG" IS '数据状态，1有效0失效';
CREATE INDEX "idx_bi_i_passenger_track_idx_bi_i_passenger_track" ON "bi_i_passenger_track" ("CAL_DATE");

DROP TABLE IF EXISTS "bi_i_pos_payment" CASCADE;

